import React ,{useState} from "react";

import {Tooltip ,Grow, KeyboardArrowDown, KeyboardDoubleArrowUp } from "@mui/icons-material"


import { watchlist } from "../data/data";


function WatchList() {
  return (  
    <div className="watchlist-container">
      <div className="search-container">
        <input
          type="text"
          name="search"
          id="search"
          placeholder="Search eg:infy, bse, nifty fut weekly, gold mcx"
          className="search"
        />
        <span className="counts"> {watchlist.length} / 50</span>
      </div>

      <ul className="list">
        {watchlist.map((stock,index)=>{
          return (
          <WatchListItem stock={stock} key={index}/>
          );

        })}
      </ul>
    </div>

  );
};

export default WatchList;

const WatchListItem=({stock})=>{
  const [showWatchListItem ,setshowWatchListItem]=useState(false);

  const handleMouseEnter=(e)=>{
    setshowWatchListItem(true);
  }
  const handleMouseExit=(e)=>{
    setshowWatchListItem(false);
  }

  return(
    <li onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseExit}> 
      <div className="item">
        <p className={stock.isDown ? "down" : "up"}>{stock.name}</p>
        <div className="itemInfo">
          <span className="percent">{stock.percent}</span>
          {stock.isDown ?  <KeyboardArrowDown className="down"/>:<KeyboardDoubleArrowUp className="up"/>}
          <span className="price">{stock.price}</span>
        </div>
      </div>
    </li>

  )
}



const WatchListAction=({uid})=>{
  return(
    <span className="actions"> \
    <span>
      <Tooltip title="buy ()">
        <button className="buy">Buy</button>
        <button>sell</button>
      </Tooltip>

    </span>
    </span>
  )

}
